def _with_timeout(fn, timeout: float, what: str):
    """Run a sync callable with a hard timeout; raise ReasoningError on overrun.

    Propagates the current OpenTelemetry context into the worker thread so spans
    created by fn (e.g. the LangChain ChatOllama span) nest under the active
    reasoning.complete span instead of being orphaned (#238).
    """
    from opentelemetry import context as otel_context

    ctx = otel_context.get_current()

    def _run():
        token = otel_context.attach(ctx)
        try:
            return fn()
        finally:
            otel_context.detach(token)

    future = _submit_bounded(_run)
    try:
        return future.result(timeout=timeout)
    except FuturesTimeout as exc:
        raise ReasoningError(f"{what} timed out after {timeout:.0f}s") from exc


def _run_sync(coro: Any) -> Any:
    """Run a coroutine to completion from sync code, even inside a running loop."""
    try:
        asyncio.get_running_loop()
    except RuntimeError:
        return asyncio.run(coro)

def _record_usage(span, usage: Any) -> None:
    """Set OpenInference token-count attributes from a usage dict/object (#203)."""
    if not usage:
        return

    def g(key: str):
        return usage.get(key) if isinstance(usage, dict) else getattr(usage, key, None)

    prompt_toks = g("input_tokens")
    completion_toks = g("output_tokens")
    # Anthropic/Agent-SDK report cache tokens in SEPARATE fields excluded from
    # input_tokens; on a cached-prefix run they can dominate real input. Fold them
    # into the prompt/total counts (and emit the OpenInference cache slots) so
    # llm.token_count.total reflects all tokens processed, not an undercount on the
    # very tier where usage visibility matters most (#280). Real spend is still
    # tracked separately via llm.cost_usd.
    cache_read = g("cache_read_input_tokens")
    cache_write = g("cache_creation_input_tokens")
    if cache_read is not None:
        span.set_attribute("llm.token_count.prompt_details.cache_read", cache_read)
    if cache_write is not None:
        span.set_attribute("llm.token_count.prompt_details.cache_write", cache_write)

    prompt_total = None
    if prompt_toks is not None or cache_read is not None or cache_write is not None:
        prompt_total = (prompt_toks or 0) + (cache_read or 0) + (cache_write or 0)
        span.set_attribute("llm.token_count.prompt", prompt_total)
    if completion_toks is not None:
        span.set_attribute("llm.token_count.completion", completion_toks)
    if prompt_total is not None and completion_toks is not None:
        span.set_attribute("llm.token_count.total", prompt_total + completion_toks)

with _tracer.start_as_current_span("reasoning.complete_json") as span:
    span.set_attribute("hcgrc.tier", tier.value)
    if run_id:
        span.set_attribute("hcgrc.run_id", run_id)
        span.set_attribute("session.id", run_id)  # mirror complete() (pass-6)
    if agent_id:
        # Mirror complete()'s child span so the parent carries the same
        # correlation id, not just its children (pass-5).
        span.set_attribute("hcgrc.agent_id", agent_id)
    for attempt in range(MAX_RETRIES + 1):
        # Vary decoding across regenerations so a retry can actually differ from
        # the prior attempt (#275). A plain min(1.0, temp + bump) saturates at
        # 1.0 for high input temperatures, making retries identical again
        # (pass-5); when the upward bump would exceed 1.0, bump DOWNWARD instead
        # so every attempt gets a distinct, in-range temperature.
        if attempt == 0:
            attempt_temp = temperature
        else:
            bump = 0.2 * attempt
            attempt_temp = (temperature + bump if temperature + bump <= 1.0
                            else max(0.0, temperature - bump))
        try:
            raw = complete(
                tier, prompt, system=json_system, temperature=attempt_temp,
                max_turns=max_turns, model=model, run_id=run_id, agent_id=agent_id,
                _json_mode=True,
            )
        except ReasoningError as exc:
